import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return empty array for empty input");
  it.todo("should return empty array for a single live cell (underpopulation)");
  it.todo("should return empty array for two adjacent live cells (underpopulation)");
  it.todo("should create a new live cell at a dead position with exactly 3 live neighbors (reproduction)");
  it.todo("should keep a live cell alive when it has 2 or 3 live neighbors (survival)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should keep a block still life unchanged: [(0,0),(1,0),(0,1),(1,1)] stays the same");
  it.todo("should oscillate a blinker: [(0,0),(0,1),(0,2)] becomes [(-1,1),(0,1),(1,1)]");
});
